css:
* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}
body {
  font-family: 'Segoe UI', Arial, sans-serif;
  font-size: 13px;
  color: #1a1a2e;
  background: #fff;
}
.receipt {
  max-width: 380px;
  margin: 0 auto;
  padding: 20px 16px;
}
.header {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 10px;
  padding-bottom: 14px;
}
.logo {
  width: 80px;
  height: 80px;
  object-fit: contain;
}
.receipt-label {
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 4px;
  color: #6b7280;
  text-transform: uppercase;
  text-align: center;
}
.queue-no {
  font-size: 30px;
  font-weight: 900;
  color: #1a1a2e;
  letter-spacing: 3px;
  text-align: center;
}
.divider-solid {
  border: none;
  border-top: 2px solid #1a1a2e;
  margin: 10px 0;
}
.divider-dash {
  border: none;
  border-top: 1px dashed #d1d5db;
  margin: 10px 0;
}
.info-grid {
  display: flex;
  flex-direction: column;
  gap: 5px;
  padding: 2px 0;
}
.info-row {
  display: flex;
  justify-content: space-between;
  align-items: baseline;
}
.info-label {
  font-size: 10px;
  font-weight: 700;
  color: #9ca3af;
  text-transform: uppercase;
  letter-spacing: 0.5px;
  min-width: 65px;
  flex-shrink: 0;
}
.info-value {
  font-size: 12px;
  color: #1a1a2e;
  font-weight: 500;
  text-align: right;
}
.items-table {
  width: 100%;
  border-collapse: collapse;
  margin: 4px 0;
}
.items-table th {
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 1px;
  text-transform: uppercase;
  color: #9ca3af;
  padding: 7px 4px;
  text-align: left;
  border-bottom: 1px solid #e5e7eb;
}
.items-table td {
  font-size: 13px;
  color: #1a1a2e;
  padding: 10px 4px;
  font-weight: 500;
}
.r { text-align: right; }
.totals {
  display: flex;
  flex-direction: column;
  gap: 7px;
  padding: 2px 0;
}
.total-row {
  display: flex;
  justify-content: space-between;
  font-size: 13px;
  color: #374151;
}
.total-row.green {
  color: #059669;
  font-weight: 600;
}
.total-row.big {
  font-size: 15px;
  font-weight: 800;
  color: #1a1a2e;
  border-top: 2px solid #1a1a2e;
  padding-top: 8px;
  margin-top: 2px;
}
.footer {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 3px;
  padding-top: 6px;
  text-align: center;
}
.invoice-ref {
  font-size: 12px;
  font-weight: 700;
  color: #374151;
  letter-spacing: 1px;
}
.thank-you {
  font-size: 14px;
  font-weight: 700;
  color: #1a1a2e;
  margin-top: 6px;
}
.brand {
  font-size: 10px;
  color: #d1d5db;
  margin-top: 10px;
}
.website {
  font-size: 10px;
  color: #d1d5db;
}
@media print {
  .receipt { max-width: 100%; padding: 8px; }
}
